import{_ as t,c as i,o as s,ag as l}from"./chunks/framework.BZfAkMaX.js";const c=JSON.parse('{"title":"基于vitepress的个人简历","description":"","frontmatter":{"outline":"deep","sidebar":false,"aside":"left"},"headers":[],"relativePath":"guide/mdlearn/vpdemo/01.resumeDoc.md","filePath":"guide/mdlearn/vpdemo/01.resumeDoc.md","lastUpdated":null}'),e={name:"guide/mdlearn/vpdemo/01.resumeDoc.md"};function n(r,a,o,d,h,p){return s(),i("div",null,a[0]||(a[0]=[l(`<h1 id="基于vitepress的个人简历" tabindex="-1">基于vitepress的个人简历 <a class="header-anchor" href="#基于vitepress的个人简历" aria-label="Permalink to &quot;基于vitepress的个人简历&quot;">​</a></h1><h2 id="安装-vitepress" tabindex="-1">安装 vitepress <a class="header-anchor" href="#安装-vitepress" aria-label="Permalink to &quot;安装 vitepress&quot;">​</a></h2><ul><li><a href="https://vitepress.dev/zh/guide/getting-started#installation" target="_blank" rel="noreferrer">🚀</a></li></ul><ol><li>安装 vitepress</li></ol><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">yarn</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> add</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -D</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> vitepress</span></span></code></pre></div><ol start="2"><li>安装导向</li></ol><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">yarn</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> vitepress</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> init</span></span></code></pre></div><ol start="3"><li>启动</li></ol><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">yarn</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> docs:dev</span></span></code></pre></div><p>或者</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">yarn</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> vitepress</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> dev</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> docs</span></span></code></pre></div><h2 id="简历-📝✨" tabindex="-1">简历 📝✨ <a class="header-anchor" href="#简历-📝✨" aria-label="Permalink to &quot;简历  📝✨&quot;">​</a></h2><h3 id="分析" tabindex="-1">分析 <a class="header-anchor" href="#分析" aria-label="Permalink to &quot;分析&quot;">​</a></h3><ul><li><p>首先，需要考虑<strong>身份</strong>。</p><ul><li>可能是在找工作的<strong>应届毕业生</strong>，或者是有一定工作经验要<strong>跳槽</strong>的人。</li></ul></li><li><p>接下来，需求是什么？</p><ul><li>简历包含哪些部分，每个部分应该放什么信息。</li><li>深层需求是希望简历看起来更<strong>专业</strong>，<strong>符合招聘方的期望，提高通过筛选的机会</strong>。</li></ul></li><li><p>之后，分析需求</p><ul><li><strong>根据不同岗位调整模块顺序和内容</strong>，比如技术岗突出项目经验，设计岗强调作品集</li><li>需要给出具体的例子，比如如何用数据展示成果，如何根据岗位描述调整关键词。</li><li>可能他们的简历需要中英文版本，需要考虑排版和语言规范。</li></ul></li><li><p>最后，要确<strong>保简历结构清晰，能够轻松找到所需信息</strong>。</p></li></ul><h3 id="内容" tabindex="-1">内容 <a class="header-anchor" href="#内容" aria-label="Permalink to &quot;内容&quot;">​</a></h3><ul><li>简历内容应与目标岗位匹配，突出与岗位相关的核心技能和经验。</li><li>可以使用<strong>关键词</strong>来突出重点，如“创新”、“团队合作”等。</li><li>可以使用<strong>图表</strong>和<strong>数据可视化</strong>来展示项目成果和经验。</li></ul><h3 id="示例" tabindex="-1">示例 <a class="header-anchor" href="#示例" aria-label="Permalink to &quot;示例&quot;">​</a></h3><p>🔥 一份标准的个人简历通常包含以下核心模块和信息，根据求职者经验与目标岗位的不同，模块顺序和内容可灵活调整：</p><h4 id="_1-个人信息-必填" tabindex="-1"><strong>1. 个人信息(必填)</strong> <a class="header-anchor" href="#_1-个人信息-必填" aria-label="Permalink to &quot;**1. 个人信息(必填)**&quot;">​</a></h4><ul><li>基本信息： 姓名、联系方式（电话/邮箱）、求职意向（明确岗位名称）</li><li>可选补充： <ul><li>居住地</li><li>个人网站/作品集链接（设计、技术岗建议附上）</li><li>出生日期</li></ul></li><li>例如<br><code>张琳 | 📞 138-1234-5678 | 📧 &lt;zhanglin@email.com&gt; 📍 上海 | 🔗 作品集：www.zhanglin.design 求职意向：UI/UX设计师（3年经验）</code></li></ul><h4 id="_2-教育背景" tabindex="-1">2. <strong>教育背景</strong> <a class="header-anchor" href="#_2-教育背景" aria-label="Permalink to &quot;2. **教育背景**&quot;">​</a></h4><ul><li><strong>学历信息</strong>：学校名称、学位（本科/硕士等）、专业、就读时间</li><li><strong>补充亮点</strong>： <ul><li>GPA（若高于3.3/4.0或排名前20%）</li><li>核心课程（仅应届生或与岗位强相关时列出）</li><li>荣誉奖项（奖学金、竞赛获奖等）</li></ul></li><li>示例</li></ul><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>上海交通大学 | 硕士 | 计算机科学与技术 | 2019.09–2022.06  </span></span>
<span class="line"><span></span></span>
<span class="line"><span>- GPA：3.8/4.0（专业前5%）  </span></span>
<span class="line"><span>- 相关课程：人机交互、数据结构、机器学习  </span></span>
<span class="line"><span>- 荣誉：国家奖学金（2021）</span></span></code></pre></div><h4 id="_3-工作经历" tabindex="-1">3. <strong>工作经历</strong> <a class="header-anchor" href="#_3-工作经历" aria-label="Permalink to &quot;3. **工作经历**&quot;">​</a></h4><ul><li><p><strong>公司信息</strong>:</p><ul><li>公司名称</li><li>岗位名称</li><li>在职时间（精确到月）</li></ul></li><li><p>工作内容</p><ul><li>（用“动词+成果+数据”描述）</li><li>突出与目标岗位相关的核心职责</li><li>分点陈述（每段经历3-5点，按重要性降序排列）</li></ul></li><li><p>示例</p></li></ul><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>腾讯科技 | 高级产品经理 | 2020.07–2024.06  </span></span>
<span class="line"><span>- 负责微信支付商户端产品迭代，推动年交易额增长25%（从800亿至1000亿）  </span></span>
<span class="line"><span>- 协调10人跨部门团队，3个月内上线风控系统，降低欺诈率15%</span></span></code></pre></div><h4 id="_4-项目经验-技术-研发岗必填" tabindex="-1">4. <strong>项目经验</strong>（技术/研发岗必填） <a class="header-anchor" href="#_4-项目经验-技术-研发岗必填" aria-label="Permalink to &quot;4. **项目经验**（技术/研发岗必填）&quot;">​</a></h4><p>​- <strong>项目名称</strong>、角色（负责人/核心成员）、时间</p><ul><li><strong>​项目描述</strong>：技术栈、目标、量化成果</li><li><strong>​适用场景</strong>： <ul><li>应届生无全职经历时替代“工作经历”</li><li>社招人员展示与岗位相关的独立项目或跨部门协作项目</li></ul></li></ul><h4 id="_5-技能与证书" tabindex="-1">5. <strong>技能与证书</strong> <a class="header-anchor" href="#_5-技能与证书" aria-label="Permalink to &quot;5. **技能与证书**&quot;">​</a></h4><ul><li>技术类（编程语言、工具）</li><li>语言类（英语、其他语言）</li><li>证书类（PMP、CFA、行业认证等）</li><li>⚠️ ​注意：避免“精通Office”等基础技能，除非岗位明确要求</li></ul><h4 id="_6-其他可选模块" tabindex="-1">6.<strong>其他可选模块</strong> <a class="header-anchor" href="#_6-其他可选模块" aria-label="Permalink to &quot;6.**其他可选模块**&quot;">​</a></h4><table tabindex="0"><thead><tr><th>模块名称</th><th>适用场景</th><th>示例内容</th></tr></thead><tbody><tr><td>自我评价</td><td>转行/跨领域求职时快速突出优势</td><td>“5年跨境电商运营经验，熟悉欧美市场用户增长策略”</td></tr><tr><td>获奖荣誉</td><td>应届生/竞赛经历丰富者</td><td>“全国大学生创业大赛金奖（2022）”</td></tr><tr><td>附加信息</td><td>展示个人特质或与岗位相关的兴趣</td><td>- 技术博客（日均UV 1000+） - 开源社区贡献者</td></tr><tr><td>​志愿者经历</td><td>公益组织经历、体现软实力</td><td>“国际红十字会志愿者，累计服务200小时”</td></tr></tbody></table><h4 id="_7-附加信息" tabindex="-1">7. <strong>附加信息</strong> <a class="header-anchor" href="#_7-附加信息" aria-label="Permalink to &quot;7. **附加信息**&quot;">​</a></h4><ul><li>个人介绍（简洁自我介绍，突出与目标岗位匹配的特质）</li><li>兴趣爱好（与目标岗位相关的爱好，如摄影、绘画等）</li><li>其他（如获奖情况、个人经历等）</li></ul><h3 id="模块顺序建议" tabindex="-1">模块顺序建议 <a class="header-anchor" href="#模块顺序建议" aria-label="Permalink to &quot;模块顺序建议&quot;">​</a></h3><ul><li><strong>根据不同求职者背景灵活调整优先级：</strong></li></ul><table tabindex="0"><thead><tr><th>求职者类型</th><th>推荐模块顺序</th></tr></thead><tbody><tr><td>应届生</td><td>教育背景 → 实习经历 → 项目经验 → 技能</td></tr><tr><td>社招（同行业）</td><td>工作经历 → 项目经验 → 技能 → 教育背景</td></tr><tr><td>转行/跨领域</td><td>技能/证书 → 相关项目经验 → 工作经历</td></tr></tbody></table><h3 id="避坑指南" tabindex="-1"><strong>避坑指南</strong> <a class="header-anchor" href="#避坑指南" aria-label="Permalink to &quot;**避坑指南**&quot;">​</a></h3><p>• ❌ 写“期望薪资”（面试前不宜透露）<br> • ❌ 放证件照（除非外企或岗位明确要求）<br> • ❌ 使用“个人简历”作为标题（直接写姓名更专业）<br> • ❌ 大段文字描述（用分点+关键词提高可读性）</p><h3 id="建议" tabindex="-1"><strong>建议</strong> <a class="header-anchor" href="#建议" aria-label="Permalink to &quot;**建议**&quot;">​</a></h3><ul><li>✅ 文件命名于格式： <ul><li>✅ 命名：姓名_岗位_年限_电话.pdf（例：王小明_高级产品经理_5年_13812345678.pdf）</li><li>✅ 格式：PDF优先（避免格式错乱），字号11-12pt，页边距0.5-1英寸。</li></ul></li><li>​✅ 关键词匹配：根据招聘JD（职位描述）调整技能和经历关键词。</li><li>✅ 量化成果：用数据（百分比、金额、用户量）代替模糊描述。</li><li>✅ 一页原则：应届生/初级岗位控制1页，资深人士不超过2页。</li></ul>`,42)]))}const g=t(e,[["render",n]]);export{c as __pageData,g as default};
